async function main() {
  console.log('\n🔧 Cargando pronósticos correctos para todos los jugadores...\n')
  
  let totalOk = 0, totalErr = 0

  for (const j of JUGADORES) {
    const rows = j.preds.map(p => ({
      usuario_id:      j.uid,
      partido_id:      p.pid,
      goles_local:     p.gl,
      goles_visitante: p.gv,
    }))

    const { error } = await supabase
      .from('pronosticos')
      .upsert(rows, { onConflict: 'usuario_id,partido_id' })

    if (error) {
      console.error(`  ✗ ${j.nombre}: ${error.message}`)
      totalErr++
    } else {
      console.log(`  ✓ ${j.nombre}: ${rows.length} pronósticos`)
      totalOk++
    }

    await new Promise(r => setTimeout(r, 50))
  }

  console.log(`\n✅ Listo. ${totalOk} jugadores OK, ${totalErr} errores.`)
  console.log('   Cada jugador ahora tiene exactamente 72 pronósticos de fase de grupos.')
}

main().catch(console.error)
